def _blank(ctx, message, title="无可绘制数据", filename="empty_chart.png"):
    fig, ax = ctx.plt.subplots(figsize=(6.5, 4.2))
    ax.text(0.5, 0.5, message, ha="center", va="center", fontsize=12, color="#374151")
    ax.axis("off")
    fig.tight_layout()
    return ctx.figure(fig, filename=filename, title=title)


def _tone_parts(group):
    text = str(group or "").replace("＋", "+").replace("/", "+").replace("、", "+")
    if "+" not in text:
        return None, None
    parts = []
    for part in text.split("+"):
        value = part.strip()
        if value:
            parts.append(value)
    if len(parts) < 2:
        return None, None
    return parts[0], parts[1]


def _clean(ctx, value):
    try:
        number = float(value)
    except Exception:
        return None
    if ctx.np.isfinite(number):
        return number
    return None


def _ordered_tones(items):
    tones = []
    for item in items:
        front, back = _tone_parts(item.get("group", ""))
        for tone in [front, back]:
            if tone and tone not in tones:
                tones.append(tone)
    return tones


def _point_x(syl_index, point_index):
    percent = 5.0 + point_index * 9.0
    if syl_index == 0:
        return percent
    return 100.0 + percent


def _add_time_axis(axis):
    axis.axvline(100.0, color="#666666", linewidth=1.0, linestyle="--")
    axis.set_xlim(0, 200)
    axis.set_xticks([5, 50, 95, 105, 150, 195])
    axis.set_xticklabels(["前字5%", "前字50%", "前字95%", "后字5%", "后字50%", "后字95%"])
    axis.set_ylim(0.8, 5.2)
    axis.set_yticks([1, 2, 3, 4, 5])
    axis.set_ylabel("五度值")
    axis.grid(True, linestyle="--", alpha=0.25, linewidth=0.8)


def _collect_rows(ctx, items):
    rows = []
    for item in items:
        front, back = _tone_parts(item.get("group", ""))
        if not front or not back:
            continue
        syl_t = item.get("syl_t_values", [])
        if len(syl_t) < 2:
            continue
        for syl_index in range(2):
            points = syl_t[syl_index]
            limit = min(11, len(points))
            for point_index in range(limit):
                value = _clean(ctx, points[point_index])
                if value is None:
                    continue
                rows.append({
                    "item": item,
                    "speaker": item.get("speaker_name", "发音人"),
                    "label": str(item.get("label", "")).strip(),
                    "front": front,
                    "back": back,
                    "syl": syl_index + 1,
                    "x": _point_x(syl_index, point_index),
                    "value": value,
                })
    return rows


def _mean(values):
    if not values:
        return None
    return float(sum(values) / len(values))


def _mean_ci(ctx, values):
    arr = ctx.np.asarray(values, dtype=float)
    mean = float(ctx.np.mean(arr))
    if len(values) > 1:
        std = float(ctx.np.std(arr))
    else:
        std = 0.0
    se = std / float(ctx.np.sqrt(len(values)))
    low = max(1.0, min(5.0, mean - 1.96 * se))
    high = max(1.0, min(5.0, mean + 1.96 * se))
    return mean, low, high


def _structure_for_item(item):
    for key in ["structure_main", "结构大类", "structure_type", "结构类型"]:
        value = item.get(key)
        if value:
            return str(value), str(value)
    label = str(item.get("label", "")).strip()
    mapped = STRUCTURE_MAP.get(label)
    if mapped:
        return mapped[0], mapped[1]
    return "未分类", "未分类"


def _valid_syllable_count(ctx, item, syl_index):
    syl_t = item.get("syl_t_values", [])
    if len(syl_t) <= syl_index:
        return 0
    count = 0
    for value in syl_t[syl_index]:
        if _clean(ctx, value) is not None:
            count += 1
    return count


def run(ctx):
    all_items = list(ctx.dataset.items)
    if not all_items:
        return _blank(ctx, "当前工程没有可供脚本读取的条目。")
    tones = _ordered_tones(all_items)
    if not tones:
        tones = ["未分组"]
    tone_index = {tone: index for index, tone in enumerate(tones)}
    matrix = ctx.np.zeros((len(tones), len(tones)), dtype=float)
    status_order = ["纳入", "数据不足", "排除"]
    status_colors = {"纳入": "#4C78A8", "数据不足": "#F58518", "排除": "#E45756"}
    speaker_status = {}
    for item in all_items:
        speaker = item.get("speaker_name", "发音人")
        if speaker not in speaker_status:
            speaker_status[speaker] = {status: 0 for status in status_order}
        front, back = _tone_parts(item.get("group", ""))
        if bool(item.get("is_excluded", False)):
            status = "排除"
        else:
            front_count = _valid_syllable_count(ctx, item, 0)
            back_count = _valid_syllable_count(ctx, item, 1)
            if front_count >= 6 and back_count >= 6:
                status = "纳入"
                if front in tone_index and back in tone_index:
                    matrix[tone_index[front], tone_index[back]] += 1
            else:
                status = "数据不足"
        speaker_status[speaker][status] += 1
    fig, axes = ctx.plt.subplots(1, 2, figsize=(15.5, 6.0))
    im = axes[0].imshow(matrix, cmap="Blues")
    axes[0].set_xticks(range(len(tones)))
    axes[0].set_yticks(range(len(tones)))
    axes[0].set_xticklabels(tones)
    axes[0].set_yticklabels(tones)
    axes[0].set_xlabel("后字调类")
    axes[0].set_ylabel("前字调类")
    axes[0].set_title("完整纳入图表的词组数", fontsize=12, fontweight="bold")
    for r in range(matrix.shape[0]):
        for c in range(matrix.shape[1]):
            axes[0].text(c, r, str(int(matrix[r, c])), ha="center", va="center")
    fig.colorbar(im, ax=axes[0], fraction=0.046, pad=0.04)
    speakers = sorted(speaker_status.keys())
    bottom = [0.0 for _ in speakers]
    x_positions = list(range(len(speakers)))
    for status in status_order:
        values = [speaker_status[speaker][status] for speaker in speakers]
        axes[1].bar(x_positions, values, bottom=bottom, label=status, color=status_colors[status])
        bottom = [bottom[i] + values[i] for i in range(len(values))]
    axes[1].set_xticks(x_positions)
    axes[1].set_xticklabels(speakers, rotation=20, ha="right")
    axes[1].set_title("各发音人条目质量概览", fontsize=12, fontweight="bold")
    axes[1].set_xlabel("发音人")
    axes[1].set_ylabel("条目数")
    axes[1].legend(title="状态")
    axes[1].grid(axis="y", alpha=0.25)
    fig.suptitle("数据覆盖与质量概览", fontsize=14, fontweight="bold")
    fig.tight_layout()
    ctx.log(f"质量概览统计条目数：{len(all_items)}。")
    return ctx.figure(fig, filename="图05_数据覆盖与质量概览.png", title="数据覆盖与质量概览")
